//line-layout.js
import { defined, utils } from '../utils/zcutils';
import { d3_lineRadial, d3_line, d3_curves } from '../core/d3-constants';
import { $Browser } from '../core/browser-detect';
import { DataProcessor } from '../core/data-processor';
import { charttype } from '../core/main-zc-init';
import { mathMax } from '../core/zc-constants';
import { getChartTypeByIndex } from '../core/charttype-helpers';
import { polarToXY } from '../polaraxis/polarutils';

export function getLineLayout(rp, serData, shiftInfo, yrangePos, paneid) {
    var chartObj = rp.chartObj,
        xscale = rp.xscale,
        yscale = rp.yscale,
        stacked = rp.stacked,
        index = rp.datasetIndex,
        axisrotated = rp.axisrotated,
        commonPlotOptions = rp.commonPlotOptions,
        yaxiscolumnorder = rp.yaxiscolumnorder,
        dataset = rp.dataset,
        systemconf = chartObj.systemConf,
        dataObject = chartObj.dataObject,
        yReversed = systemconf.chart.axes.yaxis[yaxiscolumnorder].reversed,
        plotoptions = (chartObj.seriesdata[index] || chartObj.seriesdata[0]).plotoptions,
        gvp = utils.getValueOfPlotOptions(plotoptions, commonPlotOptions),
        interpolation = $Browser.FIREFOX && serData.length == 1 ? 'linearClosed' : gvp('mode'), //Firefox fails to render path marker if 'd' has only 'M(x) (y)' ZC509
        layout;

    var cType = getChartTypeByIndex(chartObj, paneid, index),
        dataProcessorHelpers = DataProcessor.helpers,
        isCatNullX = dataProcessorHelpers.isCatNull(dataset, 'x'),
        isCatNullY = dataProcessorHelpers.isCatNull(dataset, 'y', yaxiscolumnorder);

    // let isConnectedEnd = true,
    //     curve,
    //     movesCount = 1,
    //     data_len = serData.length;

    if (dataObject.isPolarAxisCategory) {
        layout = d3_lineRadial()
            .defined(function(d, j) {
                return !d.isDummy
                // // curve._index = j;
                // var isValidData = !d.isDummy && !isCatNullY(dataset.getY(d, yaxiscolumnorder)) && !isCatNullX(dataset.getX(d));   //* returns false if data is null
                // if ((j === 0 || j === data_len - 1) && !isValidData) { 
                //     isConnectedEnd = false; 
                // }
                // !isValidData ? movesCount++ : null;
                // return isValidData;
            })
            .radius(function(d, j) {
                var adjustFactor = 0.1; // #ZC717 -> if path contains 'L0,0L0,0L0,0Z'
                var r = stacked
                    ? yscale(d.y + d.y0)
                    : yscale(dataset.getY(d, yaxiscolumnorder)) + (yscale.bandwidth != null ? yscale.bandwidth() / 2 : 0);
                let radius = mathMax(r, yscale.range()[yReversed && !stacked ? yscale.domain().length - 1 : 0] + adjustFactor);
                return radius;
            })
            .angle(function(d, j) {
                return xscale(dataset.getX(d));
            })
            .curve(d3_curves(interpolation, axisrotated));
            // layout.curve(function() {
            //     curve = d3_curves(interpolation, axisrotated).apply(this, arguments);
            //     const closePath = curve._context.closePath;

            //     let args = [serData?.[0], 0, serData],
            //         [radius, angle] = data_len ? [layout.radius().apply(null, args), layout.angle().apply(null, args)] : [],
            //         startPoint = [radius * Math.sin(angle), radius * -Math.cos(angle)];

            //     curve._context.closePath = function closePath$zc() {
            //         const isLastPoint = curve._index === (data_len - 1);
            //         if ((movesCount > 1 || !isConnectedEnd) && this._x1 !== null && isLastPoint) {
            //             if (isConnectedEnd) {
            //                 this.lineTo.apply(this, startPoint);
            //             }
            //         } else {
            //             closePath.apply(this, arguments);
            //         }
            //         if (isLastPoint) {
            //             curve._context.closePath = closePath;   //* restoring closePath API in canvas context - FEATURESEVENTS_WEB_2
            //         }
            //     }
            //     return curve;
            // });
    } else {
        layout = d3_line()
            .defined(function(d, j) {
                var nullData = !isCatNullY(dataset.getY(d, yaxiscolumnorder)) && !isCatNullX(dataset.getX(d));
                if (cType.value === charttype.stkdarea) {
                    if (d.isDummy && (d.isPrevDummy && d.isNextDummy)) {
                        // to remove stacked area with dummy data added - remove stroke line join
                        return false;
                    }
                    return true;
                }
                return !d.isDummy && nullData;
            })
            .x(function(d, j) {
                var x = dataObject.getXYvalue(axisrotated, stacked, xscale, yscale, yaxiscolumnorder, d, 'x', null, yrangePos);
                if (shiftInfo != null) {
                    var transX = Math.abs(
                        dataObject.getXYvalue(
                            axisrotated,
                            stacked,
                            chartObj.renderer[index].oldXscale,
                            yscale,
                            yaxiscolumnorder,
                            serData[0],
                            'x',
                            null,
                            yrangePos
                        ) - dataObject.getXYvalue(axisrotated, stacked, xscale, yscale, yaxiscolumnorder, serData[0], 'x', null, yrangePos)
                    );
                    x = x + transX;
                }
                return x;
            })
            .y(function(d, j) {
                return chartObj.dataObject.getXYvalue(axisrotated, stacked, xscale, yscale, yaxiscolumnorder, d, 'y', null, yrangePos);
            })
            .curve(d3_curves(interpolation, axisrotated, commonPlotOptions.tension));
    }
    return layout;
}
